solution.code:
def to_snake_case(s):
    res = ""
    for i, char in enumerate(s):
        if char.isupper():
            if i > 0: res += "_"
            res += char.lower()
        else:
            res += char
    return res

if __name__ == "__main__":
    print(f"Pascal -> {to_snake_case('Pascal')}")
